from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    # Search for the Inbound Receiving Log file broadly
    xlsx_files = list(Path(workspace_path).glob('**/*nbound*eceiving*og*.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('**/Inbound_Receiving_Log.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('**/inbound_receiving_log.xlsx'))
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('**/*.xlsx') if 'inbound' in f.name.lower() or 'receiving' in f.name.lower()]
    if not xlsx_files:
        # Try any xlsx
        xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No Inbound_Receiving_Log.xlsx file found in workspace'}

    # Try each xlsx file to find the one with our manifest
    target_row = None
    row_num = None
    ws = None
    wb = None
    found_file = None

    for xlsx_file in xlsx_files:
        try:
            wb_candidate = openpyxl.load_workbook(xlsx_file, data_only=True)
            ws_candidate = wb_candidate.active
            for row in ws_candidate.iter_rows():
                for cell in row:
                    if cell.value and '2026-04-15-001' in str(cell.value):
                        target_row = row
                        row_num = cell.row
                        ws = ws_candidate
                        wb = wb_candidate
                        found_file = xlsx_file
                        break
                if target_row:
                    break
            if target_row:
                break
        except Exception:
            continue

    if not target_row:
        return {'pass': False, 'score': 0.0, 'feedback': 'No row found with manifest 2026-04-15-001 in any xlsx file'}

    def get_cell_val(col_idx):
        return ws.cell(row=row_num, column=col_idx).value

    # Build header map to find columns by name
    header_map = {}
    for cell in ws[1]:
        if cell.value:
            header_map[str(cell.value).strip().lower()] = cell.column

    # Standard column mapping: F=6, G=7, H=8, I=9, J=10, K=11, L=12, M=13, N=14, O=15, P=16, Q=17, R=18, S=19, T=20
    col_f = get_cell_val(6)
    col_g = get_cell_val(7)
    col_h = get_cell_val(8)
    col_i = get_cell_val(9)
    col_j = get_cell_val(10)
    col_k = get_cell_val(11)
    col_l = get_cell_val(12)
    col_m = get_cell_val(13)
    col_n = get_cell_val(14)
    col_p = get_cell_val(16)
    col_q = get_cell_val(17)
    col_r = get_cell_val(18)
    col_s = get_cell_val(19)
    col_t = get_cell_val(20)

    issues = []

    # Helper for numeric checks with generous tolerance
    def check_numeric(val, expected, col_name, tolerance=None):
        if tolerance is None:
            tolerance = max(abs(expected) * 0.05, 1.0)
        try:
            # Handle various string formats
            val_str = str(val).replace(',', '').strip() if val is not None else ''
            # Remove degree symbols, F/C suffixes
            val_str = re.sub(r'[°ºFCfc]', '', val_str).strip()
            if val_str == '' or val_str.lower() == 'none':
                issues.append(f'{col_name} expected ~{expected}, got {val}')
                return
            num = float(val_str)
            if abs(num - expected) > tolerance:
                issues.append(f'{col_name} expected ~{expected}, got {val} (parsed as {num})')
        except (ValueError, TypeError):
            issues.append(f'{col_name} expected ~{expected}, got {val}')

    # Check column F = 210 (generous: ±10)
    check_numeric(col_f, 210, 'Column F', tolerance=10)

    # Check column G = -10.2 (allow whole-degree rounding: -10 is fine)
    check_numeric(col_g, -10.2, 'Column G', tolerance=1.5)

    # Check column H = -10.2
    check_numeric(col_h, -10.2, 'Column H', tolerance=1.5)

    # Check column I = -18.7 (allow -19 for rounding)
    check_numeric(col_i, -18.7, 'Column I', tolerance=2.0)

    # Check column J = -13.03 (allow -13 for rounding)
    check_numeric(col_j, -13.03, 'Column J', tolerance=2.0)

    # Check column K = Tier 1
    k_str = str(col_k).lower().strip() if col_k is not None else ''
    if 'tier' not in k_str or '1' not in str(col_k):
        issues.append(f'Column K expected Tier 1, got {col_k}')

    # Check column L = 0
    check_numeric(col_l, 0, 'Column L', tolerance=0.5)

    # Check column M = 0
    check_numeric(col_m, 0, 'Column M', tolerance=0.5)

    # Check column N = Exact Match
    n_str = str(col_n).lower().strip() if col_n is not None else ''
    if 'exact' not in n_str or 'match' not in n_str:
        issues.append(f'Column N expected Exact Match, got {col_n}')

    # Check column P = none (accept none, None, n/a, empty, 0, dash, etc.)
    p_str = str(col_p).lower().strip() if col_p is not None else ''
    if p_str not in ['none', 'n/a', '', '0', '0.0', '-', 'na', 'null', 'no']:
        issues.append(f'Column P expected none, got {col_p}')

    # Check column Q = No damage
    q_str = str(col_q).lower().strip() if col_q is not None else ''
    if 'no damage' not in q_str and 'no dmg' not in q_str and q_str == 'none':
        pass  # accept 'none' as meaning no damage
    elif 'no damage' not in q_str and 'no dmg' not in q_str and 'none' not in q_str:
        if not ('damage' in q_str and 'no' in q_str) and q_str not in ['n/a', '0', '-', 'na']:
            issues.append(f'Column Q expected "No damage", got {col_q}')

    # Check column R = P3
    r_str = str(col_r).strip().lower().replace(' ', '').replace('-', '') if col_r is not None else ''
    if 'p3' not in r_str:
        issues.append(f'Column R expected P3, got {col_r}')

    # Check column S contains Open
    s_str = str(col_s).lower().strip() if col_s is not None else ''
    if 'open' not in s_str:
        issues.append(f'Column S expected to contain Open, got {col_s}')

    # Check column T contains Open
    t_str = str(col_t).lower().strip() if col_t is not None else ''
    if 'open' not in t_str:
        issues.append(f'Column T expected to contain Open, got {col_t}')

    # Check lot codes - search all cells in the row
    all_row_text = ' '.join([str(cell.value or '') for cell in target_row])

    # Also try to find a specific "lot" column by header name
    lot_codes_val = ''
    for hdr_name, hdr_col in header_map.items():
        if 'lot' in hdr_name:
            lot_val = ws.cell(row=row_num, column=hdr_col).value
            if lot_val:
                lot_codes_val += ' ' + str(lot_val)

    # Also check column O (15) as a common lot codes location
    col_o = get_cell_val(15)
    if col_o:
        lot_codes_val += ' ' + str(col_o)

    search_text = all_row_text + ' ' + lot_codes_val

    # Check for A-20260411-01 with mismatch info
    has_20260411 = 'A-20260411-01' in search_text or '20260411' in search_text
    if not has_20260411:
        issues.append('Lot codes missing A-20260411-01 reference')
    else:
        # Check mismatch text
        if 'mismatch' not in search_text.lower():
            issues.append('Lot codes missing MISMATCH notation for lot code discrepancy')
        if 'A-20260412-01' not in search_text and '20260412' not in search_text:
            issues.append('Lot codes missing manifest lot A-20260412-01 reference in mismatch')

    # Check for A-20260410-01
    if 'A-20260410-01' not in search_text and '20260410' not in search_text:
        issues.append('Lot codes missing A-20260410-01')

    # Check for B-20260408-01
    if 'B-20260408-01' not in search_text and '20260408' not in search_text:
        issues.append('Lot codes missing B-20260408-01')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': f'Row for manifest 2026-04-15-001 in {found_file.name} has issues:\n' + '\n'.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': f'Row for manifest 2026-04-15-001 found in {found_file.name} with correct values: F={col_f}, G={col_g}, H={col_h}, I={col_i}, J={col_j}, K={col_k}, L={col_l}, M={col_m}, N={col_n}, P={col_p}, Q={col_q}, R={col_r}, S={col_s}, T={col_t}. Lot codes contain all required references including mismatch notation.'}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if not external_services_path:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path not provided; cannot check email'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': f'mailbox.json not found at {mailbox_path}'}

    with open(mailbox_path, 'r') as f:
        data = json.load(f)

    emails = data.get('emails', [])
    sent_emails = [e for e in emails if e.get('folder', '').lower() == 'sent']

    for email in sent_emails:
        to_addr = str(email.get('to_addr', '')).lower()
        cc_addr = str(email.get('cc_addr', '') or '').lower()
        body = str(email.get('body_text', '') or '').lower()
        subject = str(email.get('subject', '') or '').lower()
        combined = subject + ' ' + body

        if 'jacob.patel@prairiestar.com' not in to_addr:
            continue

        if 'carlos.mendoza@prairiestar.com' not in cc_addr:
            continue

        # Check for "LOT CODE MISMATCH" as a phrase in subject or body
        # Accept minor variations: "lot code mismatch", "lot-code mismatch", etc.
        has_lc_mismatch_phrase = bool(re.search(r'lot[\s\-_]*code[\s\-_]*mismatch', combined))

        has_manifest = '2026-04-15-001' in combined
        has_lot_manifest = 'a-20260412-01' in combined
        has_lot_received = 'a-20260411-01' in combined

        # Check for "hold receipt open" as a connected phrase (allow words in between)
        has_hold_open = bool(re.search(r'hold\s+receipt\s+open', combined))

        # Also accept "hold .* open pending clarification" as a looser but still structured match
        if not has_hold_open:
            has_hold_open = bool(re.search(r'hold\b.*?\bopen\b.*?\bpending\b.*?\bclarification\b', combined))

        missing = []
        if not has_lc_mismatch_phrase:
            missing.append('"LOT CODE MISMATCH" phrase (found only scattered keyword "mismatch")' if 'mismatch' in combined else '"LOT CODE MISMATCH" phrase')
        if not has_manifest:
            missing.append('manifest 2026-04-15-001')
        if not has_lot_manifest:
            missing.append('lot A-20260412-01')
        if not has_lot_received:
            missing.append('lot A-20260411-01')
        if not has_hold_open:
            missing.append('"Hold receipt open pending clarification" phrase')

        if not missing:
            return {'pass': True, 'score': 1.0, 'feedback': f'Found sent email to jacob.patel@prairiestar.com with cc to carlos.mendoza@prairiestar.com containing LOT CODE MISMATCH template for manifest 2026-04-15-001'}
        else:
            return {'pass': False, 'score': 0.0, 'feedback': f'Found email to jacob.patel with cc carlos.mendoza but missing: {missing}'}

    return {'pass': False, 'score': 0.0, 'feedback': f'No sent email found to jacob.patel@prairiestar.com with cc carlos.mendoza@prairiestar.com about lot code mismatch. Checked {len(sent_emails)} sent emails.'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if not external_services_path:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path not provided; cannot check Slack'}

    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': f'slack_data.json not found at {slack_path}'}

    with open(slack_path, 'r') as f:
        data = json.load(f)

    channels = data.get('channels', {})
    messages = data.get('messages', {})

    # Find target channel IDs
    target_channel_names = ['receiving-houston', 'waco-production-coord']
    target_channel_ids = []
    for ch_id, ch_info in channels.items():
        ch_name = str(ch_info.get('name', '')).lower()
        for target in target_channel_names:
            if target.lower() in ch_name or ch_name in target.lower():
                target_channel_ids.append(ch_id)
                break

    if not target_channel_ids:
        # Try to search all channels
        target_channel_ids = list(messages.keys())

    for ch_id in target_channel_ids:
        ch_msgs = messages.get(ch_id, [])
        for msg in ch_msgs:
            text = str(msg.get('text', '')).lower()
            has_p3 = 'p3' in text
            has_manifest = '2026-04-15-001' in text
            has_mismatch = 'mismatch' in text or 'lot code' in text

            if has_p3 and has_manifest and has_mismatch:
                ch_name = channels.get(ch_id, {}).get('name', ch_id)
                return {'pass': True, 'score': 1.0, 'feedback': f'Found Slack message in channel #{ch_name} mentioning P3, manifest 2026-04-15-001, and lot code mismatch'}

    # Collect what was found for feedback
    found_msgs = []
    for ch_id in list(messages.keys()):
        ch_msgs = messages.get(ch_id, [])
        for msg in ch_msgs:
            text = str(msg.get('text', '')).lower()
            if '2026-04-15-001' in text or 'p3' in text:
                found_msgs.append(f'channel {ch_id}: {msg.get("text", "")[:100]}')

    return {'pass': False, 'score': 0.0, 'feedback': f'No Slack message found in #receiving-houston or #waco-production-coord with P3, 2026-04-15-001, and mismatch. Target channels found: {target_channel_ids}. Related messages: {found_msgs[:3]}'}

from pathlib import Path
import openpyxl
import re
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    # Find the expiry tracker file (flexible naming)
    xlsx_files = list(Path(workspace_path).glob('**/expiry_tracker.xlsx')) + list(Path(workspace_path).glob('**/Expiry_Tracker.xlsx'))
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('**/*.xlsx') if 'expiry' in f.name.lower() and 'tracker' in f.name.lower()]
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('**/*.xlsx') if 'expiry' in f.name.lower() or 'tracker' in f.name.lower()]
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No expiry_tracker.xlsx file found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0], data_only=True)

    # Search across all sheets for the lot code
    target_row_num = None
    lot_col = None
    target_ws = None

    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
        for row in ws.iter_rows():
            for cell in row:
                if cell.value and 'a-20260410-01' in str(cell.value).lower().strip():
                    target_row_num = cell.row
                    lot_col = cell.column
                    target_ws = ws
                    break
            if target_row_num:
                break
        if target_row_num:
            break

    if not target_row_num or not target_ws:
        return {'pass': False, 'score': 0.0, 'feedback': 'No row found with Lot Code A-20260410-01 in expiry_tracker.xlsx'}

    ws = target_ws

    def normalize_date(val):
        if val is None:
            return None
        if isinstance(val, datetime):
            return val.strftime('%Y-%m-%d')
        s = str(val).strip()
        for fmt in ['%Y-%m-%d', '%m/%d/%Y', '%m/%d/%y', '%B %d %Y', '%b %d %Y', '%B %d, %Y', '%b %d, %Y',
                     '%Y/%m/%d', '%d-%b-%Y', '%d-%B-%Y', '%d %B %Y', '%d %b %Y', '%d/%m/%Y',
                     '%m-%d-%Y', '%Y%m%d', '%b %d, %y', '%B %d %Y', '%d-%m-%Y',
                     '%b-%d-%Y', '%B-%d-%Y', '%m.%d.%Y', '%d.%m.%Y', '%Y.%m.%d']:
            try:
                return datetime.strptime(s, fmt).strftime('%Y-%m-%d')
            except:
                pass
        return s.lower()

    # Rubric says columns A-L contain 12 items:
    # A=1: SC-001
    # B=2: Sweet Cream Prairie
    # C=3: A-20260410-01
    # D=4: H-A
    # E=5: April 15 2026
    # F=6: 2026-04-10
    # G=7: 18
    # H=8: 2027-10-10
    # I=9: 542 or 543
    # J=10: Green
    # K=11: 100
    # L=12: Monitored
    #
    # The lot code (A-20260410-01) is the 3rd item, expected in column C (col index 3).
    offset = lot_col - 3

    def get_val(expected_col):
        return ws.cell(row=target_row_num, column=expected_col + offset).value

    issues = []

    # A=1: SC-001
    a = get_val(1)
    if a is None or 'sc-001' not in str(a).lower().replace(' ', ''):
        issues.append(f'Col A expected SC-001, got {a}')

    # B=2: Sweet Cream Prairie
    b = get_val(2)
    if b is None or 'sweet cream prairie' not in str(b).lower():
        issues.append(f'Col B expected Sweet Cream Prairie, got {b}')

    # C=3: A-20260410-01 (already confirmed by search)
    c = get_val(3)
    if c is None or 'a-20260410-01' not in str(c).lower():
        issues.append(f'Col C expected A-20260410-01, got {c}')

    # D=4: H-A
    d = get_val(4)
    if d is None or 'h-a' not in str(d).lower().replace(' ', ''):
        issues.append(f'Col D expected H-A, got {d}')

    # E=5: April 15 2026 (any date format)
    e = get_val(5)
    e_norm = normalize_date(e)
    if e_norm is None or '2026-04-15' not in e_norm:
        issues.append(f'Col E expected April 15 2026, got {e} (normalized: {e_norm})')

    # F=6: 2026-04-10 (any date format)
    f_val = get_val(6)
    f_norm = normalize_date(f_val)
    if f_norm is None or '2026-04-10' not in f_norm:
        issues.append(f'Col F expected 2026-04-10, got {f_val} (normalized: {f_norm})')

    # G=7: 18
    g = get_val(7)
    try:
        g_num = float(str(g))
        if abs(g_num - 18) > 1:
            issues.append(f'Col G expected 18, got {g}')
    except:
        issues.append(f'Col G expected 18, got {g}')

    # H=8: 2027-10-10 (any date format)
    h = get_val(8)
    h_norm = normalize_date(h)
    if h_norm is None or '2027-10-10' not in h_norm:
        issues.append(f'Col H expected 2027-10-10, got {h} (normalized: {h_norm})')

    # I=9: 542 or 543
    i_val = get_val(9)
    i_ok = False
    try:
        i_num = int(round(float(str(i_val))))
        if i_num in [542, 543]:
            i_ok = True
    except:
        pass
    if not i_ok:
        if i_val is not None and str(i_val).strip() in ['542', '543']:
            i_ok = True
    if not i_ok:
        issues.append(f'Col I expected 542 or 543, got {i_val}')

    # J=10: Green
    j = get_val(10)
    if j is None or 'green' not in str(j).lower():
        issues.append(f'Col J expected Green, got {j}')

    # K=11: 100
    k = get_val(11)
    try:
        k_num = float(str(k))
        if abs(k_num - 100) > 1:
            issues.append(f'Col K expected 100, got {k}')
    except:
        issues.append(f'Col K expected 100, got {k}')

    # L=12: Monitored
    l_val = get_val(12)
    if l_val is None or 'monitored' not in str(l_val).lower():
        issues.append(f'Col L expected Monitored, got {l_val}')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': f'A-20260410-01 row issues in {xlsx_files[0].name}: ' + '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': f'A-20260410-01 row found with all correct values (A=SC-001, B=Sweet Cream Prairie, C=A-20260410-01, D=H-A, E=2026-04-15, F=2026-04-10, G=18, H=2027-10-10, I=542/543, J=Green, K=100, L=Monitored) in {xlsx_files[0].name}'}

